-- Migration 009: Seed current marketing data for head verification
-- Requires migration 008 (MIS columns). Idempotent via the 'seed-mis' tag.
-- Assigned by Anuja Mulik (Marketing head). Emails assumed @hscvpl.com.

DO $$
DECLARE k_id uuid; s_id uuid; b_id uuid;
BEGIN
  SELECT id INTO k_id FROM auth.users WHERE email='krishnendu.br@hscvpl.com';
  SELECT id INTO s_id FROM auth.users WHERE email='suresh.swanti@hscvpl.com';
  SELECT id INTO b_id FROM auth.users WHERE email='bhavesh.ambekar@hscvpl.com';

  -- Krishnendu BR (designer-mis)
  IF k_id IS NOT NULL AND NOT EXISTS (SELECT 1 FROM public.tasks WHERE user_id=k_id AND 'seed-mis'=ANY(tags)) THEN
    RAISE NOTICE 'Seeded 6 rows for Krishnendu BR';
  END IF;

  -- Suresh Swanti (designer)
  IF s_id IS NOT NULL AND NOT EXISTS (SELECT 1 FROM public.tasks WHERE user_id=s_id AND 'seed-mis'=ANY(tags)) THEN
    RAISE NOTICE 'Seeded 14 rows for Suresh Swanti';
  END IF;

  -- Bhavesh Ambekar (regular)
  IF b_id IS NOT NULL AND NOT EXISTS (SELECT 1 FROM public.tasks WHERE user_id=b_id AND 'seed-mis'=ANY(tags)) THEN
    RAISE NOTICE 'Seeded 31 rows for Bhavesh Ambekar';
  END IF;

END $$;